class Point {
  constructor(x, y) {
    this.x = x;
    this.y = y;
  }

  // Method to check if the point is at the origin
  isOrigin() {
    return this.x === 0 && this.y === 0;
  }

  // Method to get a string representation of the point
  toString() {
    return `Point(${this.x}, ${this.y})`;
  }

  // Method to calculate the distance from the origin
  distanceFromOrigin() {
    return Math.sqrt(this.x ** 2 + this.y ** 2);
  }

  // Method to check if two points are equal
  equals(otherPoint) {
    return this.x === otherPoint.x && this.y === otherPoint.y;
  }
}
```

